import psycopg2
from prometheus_client import start_http_server, Gauge
import time

# Define Prometheus metrics
db_up = Gauge('db_up', 'Whether the db is up or not', ['username', 'password', 'host', 'connection'])

def check_database(username, password, host, connection):
    try:
        conn = psycopg2.connect(dbname="your_database", user=username, password=password, host=host, port=5432)
        db_up.labels(username=username, password=password, host=host, connection=connection).set(1)
    except:
        db_up.labels(username=username, password=password, host=host, connection=connection).set(0)
    finally:
        if conn:
            conn.close()

def main():
    # Start up the server to expose metrics.
    start_http_server(8000)
    
    while True:
        check_database('your_username', 'your_password', 'localhost', 'your_connection')
        time.sleep(15)  # wait for 15 seconds before checking again

if __name__ == "__main__":
    main()